import{_ as t,o as a,c as o,a0 as i}from"./chunks/framework.NWv86GGy.js";const g=JSON.parse('{"title":"Trans-Specific Relocation Checklists","description":"Comprehensive step-by-step checklists for transgender individuals planning international relocation — document consistency strategy, transit risk, HRT at borders, stealth relocation track, and digital security.","frontmatter":{"layout":"doc","title":"Trans-Specific Relocation Checklists","description":"Comprehensive step-by-step checklists for transgender individuals planning international relocation — document consistency strategy, transit risk, HRT at borders, stealth relocation track, and digital security."},"headers":[],"relativePath":"moving-checklists.md","filePath":"moving-checklists.md","lastUpdated":1780521962000}'),r={name:"moving-checklists.md"};function n(l,e,s,c,u,d){return a(),o("div",null,[...e[0]||(e[0]=[i('<h1 id="trans-specific-relocation-checklists" tabindex="-1">Trans-Specific Relocation Checklists <a class="header-anchor" href="#trans-specific-relocation-checklists" aria-label="Permalink to &quot;Trans-Specific Relocation Checklists&quot;">​</a></h1><p>These checklists are designed for transgender individuals relocating internationally. They go beyond generic moving checklists to address the specific challenges trans people face: document inconsistency, medication at borders, transit through hostile countries, and the choice between being out or living stealth in your new country.</p><h2 id="phase-1-pre-move-planning-begin-12–24-months-before" tabindex="-1">Phase 1: Pre-Move Planning (Begin 12–24 Months Before) <a class="header-anchor" href="#phase-1-pre-move-planning-begin-12–24-months-before" aria-label="Permalink to &quot;Phase 1: Pre-Move Planning (Begin 12–24 Months Before)&quot;">​</a></h2><h3 id="_1-document-consistency-strategy" tabindex="-1">1. Document Consistency Strategy <a class="header-anchor" href="#_1-document-consistency-strategy" aria-label="Permalink to &quot;1. Document Consistency Strategy&quot;">​</a></h3><p>One of the hardest parts of trans relocation: your documents may not be consistent, and fixing them in the wrong order can cause problems.</p><ul><li><p>[ ] <strong>Audit all your documents</strong> and note gender markers and names on each:</p><ul><li>Passport</li><li>National ID card</li><li>Birth certificate</li><li>Driver&#39;s licence</li><li>Marriage/divorce certificates</li><li>Educational certificates</li><li>Professional licences</li><li>Medical records</li></ul></li><li><p>[ ] <strong>Map your document update order.</strong> The general principle:</p><ul><li><strong>Change easiest documents first</strong> (usually local/state ID, medical records, banking)</li><li><strong>Passport last</strong> — changing your passport can out you to border authorities and create transit problems</li><li><strong>Check your destination country&#39;s rules</strong> — some require consistent documents for visa applications; others are more flexible if you provide a cover letter explaining the inconsistency</li></ul></li><li><p>[ ] <strong>If updating documents would out you to family/authorities:</strong> Weigh the risk. It may be safer to leave documents unchanged and plan to update them after arrival. This is valid.</p></li><li><p>[ ] <strong>Get professional advice</strong> from a trans-friendly immigration lawyer before making document changes that could affect your ability to leave.</p></li><li><p>[ ] <strong>Consider getting documents apostilled</strong> and translated into your destination language while you still have time.</p></li></ul><h3 id="_2-transit-country-risk-assessment" tabindex="-1">2. Transit Country Risk Assessment <a class="header-anchor" href="#_2-transit-country-risk-assessment" aria-label="Permalink to &quot;2. Transit Country Risk Assessment&quot;">​</a></h3><p>Your flight path matters. Some countries&#39; transit rules can put you at risk.</p><ul><li><p>[ ] <strong>Map your likely flight route</strong> and identify transit countries</p></li><li><p>[ ] <strong>Check each transit country&#39;s entry rules:</strong></p><ul><li>Do they require a transit visa for your nationality?</li><li>Do they have anti-LGBTQ+ laws? (Check ILGA&#39;s map)</li><li>Do border officials have discretion to search devices or question travellers?</li><li>Can you avoid transiting through Russia, Hungary, Poland (some regions), or certain US states?</li></ul></li><li><p>[ ] <strong>If you must transit through a hostile country:</strong></p><ul><li>Prepare a cover story consistent with your passport gender marker</li><li>Remove Pride flags, pronoun pins, or LGBTQ+ content from carry-on</li><li>Enable full-disk encryption on all devices</li><li>Keep documents in carry-on (do not check them)</li><li>Know generic names of your medications in case questioned</li><li>Memorise, do not write down, key contact numbers</li></ul></li><li><p>[ ] <strong>Check direct flight options</strong> — a more expensive direct flight through safe airspace is worth the cost.</p></li></ul><h3 id="_3-hrt-at-borders-what-you-need-to-know" tabindex="-1">3. HRT at Borders: What You Need to Know <a class="header-anchor" href="#_3-hrt-at-borders-what-you-need-to-know" aria-label="Permalink to &quot;3. HRT at Borders: What You Need to Know&quot;">​</a></h3><p>Injectables and certain other medications are flagged by customs in some countries.</p><ul><li><p>[ ] <strong>Research which medications are controlled</strong> in your transit and destination countries:</p><ul><li><strong>Injectable estradiol (estradiol valerate, estradiol cypionate):</strong> Flagged as &quot;controlled substance&quot; in some countries. Requires a prescription and a letter explaining it is for personal use.</li><li><strong>Testosterone:</strong> Controlled in most countries. Requires a prescription and, in some cases, a special import permit.</li><li><strong>Spiro (spironolactone):</strong> Generally not controlled but may raise questions at some borders.</li><li><strong>Progesterone:</strong> Generally not controlled.</li><li><strong>Lupron/GnRH agonists:</strong> Prescription required. Less common at customs but medical documentation is wise.</li></ul></li><li><p>[ ] <strong>Prepare documentation for medication at borders:</strong></p><ul><li>Get a detailed letter from your doctor (generic name + brand name of each medication, dosage, reason prescribed)</li><li>Get the letter translated into the languages of your transit and destination countries</li><li>Keep medication in original pharmacy packaging with prescription labels</li><li>Keep a copy of the prescription itself (not just the label)</li></ul></li><li><p>[ ] <strong>Know the generic names</strong> of your medications in case you need to refill locally:</p><ul><li>Estradiol = Estradiol, E2, 17β-estradiol</li><li>Testosterone = Testosteron, T</li><li>Spironolactone = Spironolacton, Aldactone</li><li>Cyproterone acetate = Androcur, Cyprostat</li><li>Bicalutamide = Casodex</li><li>Progesterone = Progesteron, Progestan</li></ul></li><li><p>[ ] <strong>Aim for 6–12 month supply</strong> of all medications before you depart</p></li><li><p>[ ] <strong>Research local sources</strong> for your medications in your destination country (brand names, availability, prescription requirements)</p></li></ul><h3 id="_4-pre-departure-digital-security" tabindex="-1">4. Pre-Departure Digital Security <a class="header-anchor" href="#_4-pre-departure-digital-security" aria-label="Permalink to &quot;4. Pre-Departure Digital Security&quot;">​</a></h3><ul><li><p>[ ] <strong>Create a secure encrypted backup</strong> of all essential documents:</p><ul><li>Use Veracrypt (local) or Cryptomator + Proton Drive (cloud)</li><li>Do not use Google Drive, iCloud, or Dropbox for sensitive documents</li><li>Store backup on a USB drive kept separate from your main devices</li></ul></li><li><p>[ ] <strong>Audit and secure your accounts:</strong></p><ul><li>Enable 2FA on all accounts (use a hardware key or authenticator app, not SMS)</li><li>Change passwords you have shared with others</li><li>Remove connected apps that have access to your data</li><li>Check for logged-in sessions and revoke unknown ones</li></ul></li><li><p>[ ] <strong>Delete (before crossing any border):</strong></p><ul><li>Messaging histories with LGBTQ+ contacts (Signal, WhatsApp, Telegram)</li><li>Browser history, saved passwords, autofill</li><li>Photos that could identify community members</li><li>Dating apps and profiles</li><li>Cloud traces of LGBTQ+ content (if sharing devices/accounts)</li></ul></li><li><p>[ ] <strong>Set up a clean device or partition</strong> for the journey:</p><ul><li>Factory-reset phone or use a burner phone for transit</li><li>Install only essential apps</li><li>No saved contacts that could identify community members</li><li>Full-disk encryption enabled</li></ul></li><li><p>[ ] <strong>Prepare a secure communication plan:</strong></p><ul><li>Set up Signal (or another encrypted messenger) with disappearing messages on</li><li>Memorise three emergency phone numbers</li><li>Establish check-in protocol with one trusted contact</li></ul></li></ul><h3 id="_5-the-stealth-relocation-track-parallel-checklist" tabindex="-1">5. The Stealth Relocation Track (Parallel Checklist) <a class="header-anchor" href="#_5-the-stealth-relocation-track-parallel-checklist" aria-label="Permalink to &quot;5. The Stealth Relocation Track (Parallel Checklist)&quot;">​</a></h3><p>Not everyone wants to be out in their new country. This is valid. If you choose to relocate without engaging with local trans communities or being publicly out, this parallel track is for you.</p><ul><li><p>[ ] <strong>Research the social climate</strong> in your target city specifically — not just the country. Some cities within progressive countries are more conservative (e.g., Munich vs. Berlin, Valencia vs. rural Andalusia).</p></li><li><p>[ ] <strong>Choose a destination with enough population density</strong> that you can reasonably live without being recognised:</p><ul><li>Good: Berlin, London (certain areas), Toronto, Montreal, Mexico City, Buenos Aires, Auckland</li><li>Challenging: Reykjavík, Valletta, Tallinn, Ljubljana (small populations = everyone knows everyone)</li></ul></li><li><p>[ ] <strong>Do not join local trans organisations</strong> on social media connected to your real identity. Use a separate email and handle for community research.</p></li><li><p>[ ] <strong>For housing:</strong> Find a place privately (rent from a landlord, not through a trans-specific housing group). Do not tell your landlord you are trans.</p></li><li><p>[ ] <strong>For employment:</strong> Apply in your legal name on documents. If your documents are inconsistent, address this with HR privately and professionally (explain you are in the process of updating documents). Many companies will not have a problem with this in trans-friendly countries.</p></li><li><p>[ ] <strong>For healthcare:</strong> Find a GP who is &quot;trans-friendly&quot; but not &quot;trans-specialised.&quot; A good GP will treat you without making your trans identity the focus of every appointment. In Germany, Queermed lists doctors with their approach. For stealth, look for doctors marked as &quot;LGBTQ+ friendly&quot; rather than &quot;trans-specific.&quot;</p></li><li><p>[ ] <strong>Build social connections outside the trans community.</strong> Join hobby groups, language exchanges, professional networks. You can be stealth and have a rich social life.</p></li><li><p>[ ] <strong>Acknowledge the trade-off:</strong> Stealth relocation means not being able to talk openly about your past or your identity with new friends and colleagues. It means managing the constant risk of being outed. For some people this freedom is worth the cost; for others it is too isolating. Both choices are valid.</p></li></ul><h2 id="phase-2-departure-last-3-months" tabindex="-1">Phase 2: Departure (Last 3 Months) <a class="header-anchor" href="#phase-2-departure-last-3-months" aria-label="Permalink to &quot;Phase 2: Departure (Last 3 Months)&quot;">​</a></h2><h3 id="_6-medical-preparation" tabindex="-1">6. Medical Preparation <a class="header-anchor" href="#_6-medical-preparation" aria-label="Permalink to &quot;6. Medical Preparation&quot;">​</a></h3><ul><li>[ ] <strong>Get your largest possible HRT supply</strong> — 6–12 months</li><li>[ ] <strong>Get detailed medical records</strong> including blood test results, clinic letters, surgery records</li><li>[ ] <strong>Get a letter from your doctor</strong> explaining your diagnosis, treatment, and medication list (translated to destination language)</li><li>[ ] <strong>Get prescriptions in generic names</strong> (international standard)</li><li>[ ] <strong>Schedule dental checkup, eye exam, and general health check</strong> before you leave</li><li>[ ] <strong>Research how to transfer prescriptions</strong> in your destination country</li></ul><h3 id="_7-financial-preparation" tabindex="-1">7. Financial Preparation <a class="header-anchor" href="#_7-financial-preparation" aria-label="Permalink to &quot;7. Financial Preparation&quot;">​</a></h3><ul><li>[ ] <strong>Open international bank accounts</strong> (Wise, Revolut, or N26)</li><li>[ ] <strong>Transfer enough money</strong> to cover 3–6 months of expenses</li><li>[ ] <strong>Notify banks</strong> of your move (to prevent card blocks)</li><li>[ ] <strong>Research tax implications</strong> of your move (see Phase 3 of the <a href="/transit/prepare/">12–24 Month Countdown</a> for details)</li><li>[ ] <strong>Set up a budgeting system</strong> for your first year</li><li>[ ] <strong>Keep access to your home country bank account</strong> if possible (for emergencies)</li></ul><h3 id="_8-packing-strategy" tabindex="-1">8. Packing Strategy <a class="header-anchor" href="#_8-packing-strategy" aria-label="Permalink to &quot;8. Packing Strategy&quot;">​</a></h3><ul><li><p>[ ] <strong>Carry-on bag (never check this):</strong></p><ul><li>All documents (passport, birth certificate, visa paperwork)</li><li>HRT medication (with labels and doctor&#39;s letter)</li><li>Phone, laptop, chargers</li><li>One change of clothes</li><li>Emergency cash in EUR or USD</li></ul></li><li><p>[ ] <strong>Checked luggage (or ship ahead):</strong></p><ul><li>Clothing for all seasons (you may not be able to return for more)</li><li>Toiletries</li><li>Electronics (check voltage compatibility)</li><li>Small personal items</li></ul></li><li><p>[ ] <strong>Do not pack:</strong></p><ul><li>Anything you cannot carry for 2 km</li><li>Items that could identify others in your community</li><li>Anything illegal in your transit or destination country</li></ul></li></ul><h2 id="phase-3-arrival-first-30-days" tabindex="-1">Phase 3: Arrival (First 30 Days) <a class="header-anchor" href="#phase-3-arrival-first-30-days" aria-label="Permalink to &quot;Phase 3: Arrival (First 30 Days)&quot;">​</a></h2><h3 id="_9-legal-administrative" tabindex="-1">9. Legal &amp; Administrative <a class="header-anchor" href="#_9-legal-administrative" aria-label="Permalink to &quot;9. Legal &amp; Administrative&quot;">​</a></h3><ul><li>[ ] <strong>Register with local authorities</strong> (anmeldung in Germany, residencia in Spain, SNS in Portugal, kennitala in Iceland)</li><li>[ ] <strong>Apply for residence permit</strong> (if not already issued with your visa)</li><li>[ ] <strong>Open a local bank account</strong></li><li>[ ] <strong>Get a local SIM card</strong></li><li>[ ] <strong>Register with the healthcare system</strong></li><li>[ ] <strong>Apply for tax ID number</strong></li><li>[ ] <strong>Find a GP and endocrinologist</strong> (see <a href="/transit/after/">The First Year guide</a> for country-specific processes)</li></ul><h3 id="_10-healthcare-setup" tabindex="-1">10. Healthcare Setup <a class="header-anchor" href="#_10-healthcare-setup" aria-label="Permalink to &quot;10. Healthcare Setup&quot;">​</a></h3><ul><li>[ ] <strong>Find a trans-friendly GP</strong> (use local resources: Queermed in Germany, GAT in Portugal, local Facebook groups)</li><li>[ ] <strong>Schedule endocrinologist appointment</strong> (book early — wait times can be months)</li><li>[ ] <strong>Transfer prescriptions</strong> to a local pharmacy</li><li>[ ] <strong>Establish a plan for ongoing HRT monitoring</strong></li><li>[ ] <strong>Identify nearest LGBTQ+-friendly emergency room</strong></li><li>[ ] <strong>If healthcare access is delayed:</strong> Set up bridge care via GenderGP or local bridging clinic (GAT in Portugal, queer health centres in Germany)</li></ul><h3 id="_11-community-integration" tabindex="-1">11. Community &amp; Integration <a class="header-anchor" href="#_11-community-integration" aria-label="Permalink to &quot;11. Community &amp; Integration&quot;">​</a></h3><h4 id="if-you-want-to-be-out" tabindex="-1">If you want to be out: <a class="header-anchor" href="#if-you-want-to-be-out" aria-label="Permalink to &quot;If you want to be out:&quot;">​</a></h4><ul><li>[ ] Contact local trans organisations (see <a href="/transit/after/#if-you-want-to-find-trans-specific-community">The First Year guide</a> for recommendations)</li><li>[ ] Join trans-specific social groups (Facebook, WhatsApp, Discord — use a separate account if needed)</li><li>[ ] Attend a community event in the first month</li><li>[ ] Find an LGBTQ+ friendly language exchange partner</li></ul><h4 id="if-you-want-to-be-stealth" tabindex="-1">If you want to be stealth: <a class="header-anchor" href="#if-you-want-to-be-stealth" aria-label="Permalink to &quot;If you want to be stealth:&quot;">​</a></h4><ul><li>[ ] Build social connections through hobby groups, professional networks, or volunteer work</li><li>[ ] Choose friendship over activism — not every social connection needs to be about your identity</li><li>[ ] Have a simple, consistent story about your past that you can tell without lying (e.g., &quot;I moved here for work / study / adventure&quot;)</li></ul><h4 id="for-everyone" tabindex="-1">For everyone: <a class="header-anchor" href="#for-everyone" aria-label="Permalink to &quot;For everyone:&quot;">​</a></h4><ul><li>[ ] Give yourself 6 months before judging whether the move was right</li><li>[ ] Expect to feel lonely and disoriented — this is normal and temporary</li><li>[ ] Do not compare your integration speed to others&#39;</li><li>[ ] Reach out for mental health support if needed (many countries have low-cost or free counselling for residents)</li></ul><h2 id="special-considerations" tabindex="-1">Special Considerations <a class="header-anchor" href="#special-considerations" aria-label="Permalink to &quot;Special Considerations&quot;">​</a></h2><h3 id="document-inconsistency-at-borders" tabindex="-1">Document Inconsistency at Borders <a class="header-anchor" href="#document-inconsistency-at-borders" aria-label="Permalink to &quot;Document Inconsistency at Borders&quot;">​</a></h3><p>If your documents do not match (e.g., different gender markers on passport vs. birth certificate, or name change not reflected on all documents):</p><ul><li><strong>Carry a cover letter</strong> explaining the situation clearly and professionally</li><li><strong>Include proof of ongoing name/gender change process</strong> if applicable</li><li><strong>Be prepared for questions</strong> — practice answering calmly and consistently</li><li><strong>Know your rights</strong> at the border of your destination country (research this before arrival)</li></ul><h3 id="medication-and-injectables" tabindex="-1">Medication and Injectables <a class="header-anchor" href="#medication-and-injectables" aria-label="Permalink to &quot;Medication and Injectables&quot;">​</a></h3><ul><li><strong>Injectable estradiol and testosterone</strong> require special attention at customs</li><li><strong>Keep medication in original packaging</strong> with pharmacy labels</li><li><strong>Carry a doctor&#39;s letter</strong> translated into the languages of transit and destination countries</li><li><strong>Research import limits</strong> — some countries limit personal medication to 3 months supply</li></ul><h3 id="mental-health-preparation" tabindex="-1">Mental Health Preparation <a class="header-anchor" href="#mental-health-preparation" aria-label="Permalink to &quot;Mental Health Preparation&quot;">​</a></h3><ul><li><strong>Relocation is traumatising</strong>, even when it is voluntary and well-planned</li><li><strong>You may grieve your home country</strong> — this does not mean you made the wrong choice</li><li><strong>You may feel like you do not belong</strong> in your new country for the first 6–12 months</li><li><strong>You may experience imposter syndrome</strong> about your identity in a new language and culture</li><li><strong>Be honest with yourself</strong> about how you are coping, and seek help if needed</li></ul><h2 id="resources-for-your-move" tabindex="-1">Resources for Your Move <a class="header-anchor" href="#resources-for-your-move" aria-label="Permalink to &quot;Resources for Your Move&quot;">​</a></h2><h3 id="documents-legal" tabindex="-1">Documents &amp; Legal <a class="header-anchor" href="#documents-legal" aria-label="Permalink to &quot;Documents &amp; Legal&quot;">​</a></h3><ul><li><a href="https://ilga.org/maps-sexual-orientation-laws" target="_blank" rel="noreferrer">ILGA World Map</a>: Sexual orientation laws worldwide</li><li><a href="https://tgeu.org/resources/maps/" target="_blank" rel="noreferrer">TGEU Trans Rights Map</a>: Trans-specific legal data for Europe</li><li><a href="https://www.equaldex.com/equality-index" target="_blank" rel="noreferrer">Equaldex Equality Index</a>: LGBTQ+ equality scores (note: not trans-specific)</li><li><a href="https://www.unhcr.org/media/guidelines-international-protection-no-9" target="_blank" rel="noreferrer">UNHCR Guidance for LGBTQ+ Asylum</a></li></ul><h3 id="healthcare-medication" tabindex="-1">Healthcare &amp; Medication <a class="header-anchor" href="#healthcare-medication" aria-label="Permalink to &quot;Healthcare &amp; Medication&quot;">​</a></h3><ul><li><a href="https://gendergp.com" target="_blank" rel="noreferrer">GenderGP</a>: Remote HRT prescribing (bridge care)</li><li><a href="https://www.queermed.de" target="_blank" rel="noreferrer">Queermed</a>: Trans-friendly doctor directory (Germany)</li><li><a href="https://gatportugal.org" target="_blank" rel="noreferrer">GAT Portugal</a>: Trans healthcare navigation (Portugal)</li><li><a href="https://rainbowrailroad.org" target="_blank" rel="noreferrer">Rainbow Railroad</a>: Emergency evacuation</li><li><a href="https://oramrefugee.org" target="_blank" rel="noreferrer">ORAM</a>: LGBTQ+ refugee support</li></ul><h3 id="cost-of-living-practical" tabindex="-1">Cost of Living &amp; Practical <a class="header-anchor" href="#cost-of-living-practical" aria-label="Permalink to &quot;Cost of Living &amp; Practical&quot;">​</a></h3><ul><li><a href="https://www.numbeo.com" target="_blank" rel="noreferrer">Numbeo</a>: Cost of living comparisons</li><li><a href="https://www.expat.com" target="_blank" rel="noreferrer">Expat.com</a>: Expat forums and guides</li><li><a href="https://www.iatatravelcentre.com" target="_blank" rel="noreferrer">IATA Travel Centre</a>: Visa and transit requirements</li></ul><p><em>Last verified: June 2026. Laws, visa policies, and healthcare systems change. Always verify current requirements with official sources and local trans organisations before making decisions. These checklists are a framework — adapt them to your specific circumstances, destination, and risk profile.</em></p>',52)])])}const p=t(r,[["render",n]]);export{g as __pageData,p as default};
